// Volume 颜色列表 - 按顺序分配颜色（使用更深的颜色）
const volumeColorPalette: string[] = [
  '#2D8B7C',
  '#E6653D',
  '#4A6D9E',
  '#C94E8E',
  '#7BA82E',
  '#E6C020',
  '#C19A5A',
  '#7A7A7A'
]

// 备用颜色列表
const volumeColorPaletteBackup: string[] = [
  '#A7CFE8',
  '#1666A6',
  '#C3DC8C',
  '#1E9647',
  '#FDBFBB',
  '#E62E2A',
  '#FDC589',
  '#FF8800',
  '#C5B4E3',
  '#5C3FA3',
  '#FDFD94',
  '#A36F3E'
]

// 用于存储 volume 值到颜色的映射
const volumeColorCache: { [key: string]: string } = {}
let volumeColorIndex = 0

// 获取 volume 对应的颜色
const getVolumeColor = (volume: string): string => {
  if (!volume) return '#9e9e9e'
  if (volumeColorCache[volume]) return volumeColorCache[volume]

  const color = volumeColorPalette[volumeColorIndex % volumeColorPalette.length]
  volumeColorCache[volume] = color
  volumeColorIndex++
  return color
}

type Order = 'asc' | 'desc'

interface EnhancedTableProps {
  numSelected: number
  onRequestSort: (event: React.MouseEvent<unknown>, property: keyof IDataHubItem) => void
  onSelectAllClick: (event: React.ChangeEvent<HTMLInputElement>) => void
  order: Order
  orderBy: string
  rowCount: number
}

const EnhancedTableHead = (props: EnhancedTableProps) => {
  const { onSelectAllClick, order, orderBy, numSelected, rowCount, onRequestSort } = props
  const createSortHandler = (property: keyof IDataHubItem) => (event: React.MouseEvent<unknown>) => {
    onRequestSort(event, property)
  }

  return (
    <thead>
      <tr>
        <th>
          {/* Check all data */}
          {/* <Checkbox
            indeterminate={numSelected > 0 && numSelected < rowCount}
            checked={rowCount > 0 && numSelected === rowCount}
            onChange={onSelectAllClick}
            slotProps={{
              input: {
                'aria-label': 'select all desserts'
              }
            }}
            sx={{ verticalAlign: 'sub', height: '20px' }}
          /> */}
        </th>
        {headCells.map((headCell) => {
          const active = orderBy === headCell.id
          return (
            <th
              key={headCell.id}
              style={{
                borderRight: '1px solid #cfd7e1',
                alignContent: 'center',
                minWidth: headCell.width ? headCell.width : 'auto',
                textAlign: 'center'
              }}
              aria-sort={active ? ({ asc: 'ascending', desc: 'descending' } as const)[order] : undefined}>
              <Link
                underline='none'
                color='neutral'
                textColor={active ? 'primary.plainColor' : undefined}
                component='button'
                onClick={createSortHandler(headCell.id)}
                startDecorator={
                  headCell.numeric ? <ArrowDownwardIcon sx={[active ? { opacity: 1 } : { opacity: 0 }]} /> : null
                }
                endDecorator={
                  !headCell.numeric ? <ArrowDownwardIcon sx={[active ? { opacity: 1 } : { opacity: 0 }]} /> : null
                }
                sx={{
                  fontWeight: 'lg',
                  '& svg': {
                    transition: '0.2s',
                    transform: active && order === 'desc' ? 'rotate(0deg)' : 'rotate(180deg)'
                  },

                  '&:hover': { '& svg': { opacity: 1 } }
                }}>
                {headCell.label}
                {active ? (
                  <Box component='span' sx={visuallyHidden}>
                    {order === 'desc' ? 'sorted descending' : 'sorted ascending'}
                  </Box>
                ) : null}
              </Link>
            </th>
          )
        })}
      </tr>
    </thead>
  )
}

function labelDisplayedRows({ from, to, count }: { from: number; to: number; count: number }) {
  return `${from}–${to} of ${count !== -1 ? count : `more than ${to}`}`
}

function descendingComparator<T>(a: T, b: T, orderBy: keyof T) {
  if (b[orderBy] < a[orderBy]) {
    return -1
  }
  if (b[orderBy] > a[orderBy]) {
    return 1
  }
  return 0
}

function getComparator<Key extends keyof IDataHubItem>(
  order: Order,
  orderBy: Key
): (a: { [key in Key]: number | string }, b: { [key in Key]: number | string }) => number {
  return order === 'desc'
    ? (a, b) => descendingComparator(a, b, orderBy)
    : (a, b) => -descendingComparator(a, b, orderBy)
}

const TrackTable: FC<Iprops> = (props) => {
  const { data: tableData, onCallBack } = props
  const [order, setOrder] = React.useState<Order>('desc')
  const [orderBy, setOrderBy] = React.useState<keyof IDataHubItem>('cell')
  // const [selected, setSelected] = React.useState<readonly string[]>([])
  const [selected, setSelected] = React.useState<string[]>([])
  const [page, setPage] = React.useState(0)
  const [rowsPerPage, setRowsPerPage] = React.useState(50)
  const [maxWidth, setMaxWidth] = React.useState(window.innerWidth - 80)
  const [snackbarShow, setSnackbarShow] = React.useState(false)
  const [snackbarContent, setSnackbarContent] = React.useState('')

  useEffect(() => {
    window.addEventListener('resize', () => {
      setMaxWidth(window.innerWidth - 80)
    })
  }, [])

  useEffect(() => {
    setPage(0)
    console.log('tableData changed:', tableData)
  }, [tableData])

  useEffect(() => {
    onCallBack(selected)
  }, [selected])

  const onClickApply = () => {
    const selectedData = tableData.filter((item) => selected.includes(item.id))
    console.log('selectedData', selectedData)

    const isTab = window.opener === null
    // isTab ? null : window.close()
    console.log(isTab ? 'This is a new tab' : 'This is a new window')
    if (selected.length === 0) {
      setSnackbarShow(true)
      setSnackbarContent('Please select at least one data file')
    } else {
      localStorage.setItem('selectorData', JSON.stringify(selectedData))
      window.parent.postMessage({ type: 'datahub:apply' }, window.location.origin)
      setSnackbarShow(true)
      const selectedNum = selected.length
      setSnackbarContent(selectedNum + ' Data files selected successfully')
    }

    if (selected.length > 30) {
      setSnackbarShow(true)
      setSnackbarContent('You have selected more than 30 data files, please be patient')
    }
  }

  const handleRequestSort = (event: React.MouseEvent<unknown>, property: keyof IDataHubItem) => {
    const isAsc = orderBy === property && order === 'asc'
    setOrder(isAsc ? 'desc' : 'asc')
    setOrderBy(property)
  }
  const handleSelectAllClick = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.checked) {
      const newSelected = tableData.map((n) => n.id)
      setSelected(newSelected)
      return
    }
    setSelected([])
  }
  const handleClick = (event: React.MouseEvent<unknown>, name: string) => {
    const selectedIndex = selected.indexOf(name)
    let newSelected: string[] = []
    if (selectedIndex === -1) {
      newSelected = newSelected.concat(selected, name)
    } else if (selectedIndex === 0) {
      newSelected = newSelected.concat(selected.slice(1))
    } else if (selectedIndex === selected.length - 1) {
      newSelected = newSelected.concat(selected.slice(0, -1))
    } else if (selectedIndex > 0) {
      newSelected = newSelected.concat(selected.slice(0, selectedIndex), selected.slice(selectedIndex + 1))
    }
    setSelected(newSelected)
  }
  const handleChangePage = (newPage: number) => {
    setPage(newPage)
  }
  const handleChangeRowsPerPage = (event: any, newValue: number | null) => {
    setRowsPerPage(parseInt(newValue!.toString(), 10))
    setPage(0)
  }
  const getLabelDisplayedRowsTo = () => {
    if (tableData.length === -1) {
      return (page + 1) * rowsPerPage
    }
    return rowsPerPage === -1 ? tableData.length : Math.min(tableData.length, (page + 1) * rowsPerPage)
  }

  // Avoid a layout jump when reaching the last page with empty TrackTableData.
  const emptyRows = page > 0 ? Math.max(0, (1 + page) * rowsPerPage - tableData.length) : 0

  return (
    <>
      <Sheet
        variant='outlined'
        sx={{
          '--Table-firstColumnWidth': '80px',
          marginTop: '5px',
          display: { xs: 'none', sm: 'initial' },
          width: '100%',
          maxWidth: maxWidth,
          borderRadius: '8px',
          flexShrink: 1,
          overflow: 'auto',
          minHeight: 0
        }}>
        <Table
          aria-labelledby='tableTitle'
          stickyHeader
          stickyFooter
          hoverRow
          sx={{
            '& tr > *:first-child': {
              position: 'sticky',
              left: 0,
              boxShadow: '1px 0 var(--TableCell-borderColor)',
              bgcolor: 'background.surface'
            },
            '& td, & th': { whiteSpace: 'nowrap' },
            '--TableCell-headBackground': 'transparent',
            '--TableCell-selectedBackground': '#e4effc',
            '& thead th:nth-of-type(1)': {
              width: '40px'
            },
            cursor: 'pointer',
            // '& thead th:nth-of-type(2)': {
            //   width: '30%'
            // },
            // '& tr > *:nth-of-type(n+3)': { textAlign: 'right' },
            tableLayout: 'auto',
            width: '100%',
            height: '340px',
            '& thead th': {
              backgroundColor: 'white',
              fontWeight: '400',
              color: '#2f3542'
            },
            '& thead th:first-of-type': {
              backgroundColor: 'white',
              color: '#2f3542',
              borderTopLeftRadius: 0
            },
            '& th button': {
              height: '20px',
              color: '#2f3542',
              fontSize: '14px',
              fontWeight: '600'
            },
            '& td': {
              textAlign: 'center'
            },
            borderRadius: 0
          }}>
          <EnhancedTableHead
            numSelected={selected.length}
            order={order}
            orderBy={orderBy}
            onSelectAllClick={handleSelectAllClick}
            onRequestSort={handleRequestSort}
            rowCount={tableData.length}
          />
          <tbody>
            {[...tableData]
              .sort(getComparator(order, orderBy))
              .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
              .map((row, index) => {
                const isItemSelected = selected.includes(row.id)
                const labelId = `enhanced-table-checkbox-${index}`

                return (
                  <tr
                    onClick={(event) => handleClick(event, row.id)}
                    role='checkbox'
                    aria-checked={isItemSelected}
                    tabIndex={-1}
                    key={row.id}
                    style={
                      isItemSelected
                        ? ({
                            '--TableCell-dataBackground': 'var(--TableCell-selectedBackground)',
                            '--TableCell-headBackground': 'var(--TableCell-selectedBackground)'
                          } as React.CSSProperties)
                        : {}
                    }>
                    <th scope='row'>
                      <Checkbox
                        checked={isItemSelected}
                        slotProps={{
                          input: {
                            'aria-labelledby': labelId
                          }
                        }}
                        sx={{ verticalAlign: 'top' }}
                      />
                    </th>
                    {tableKeys.map((key) => {
                      if (key === 'doi') {
                        return (
                          <td key={`${key}-${row.id}`}>
                            <Tooltip title={row[key] || 'No DOI available'}>
                              <Link
                                href={row[key] ? `https://doi.org/${row[key]}` : undefined}
                                target='_blank'
                                rel='noopener'
                                underline='hover'
                                color='primary'>
                                {row[key] || ''}
                              </Link>
                            </Tooltip>
                          </td>
                        )
                      } else if (key === 'condition') {
                        // 处理 tags 列，显示为徽标
                        const tags = row[key]
                          ? row[key]
                              .split(',')
                              .map((tag) => tag.trim())
                              .filter((tag) => tag)
                          : []
                        return (
                          <td key={`${key}-${row.id}`}>
                            <Box
                              sx={{
                                display: 'flex',
                                gap: 0.5,
                                flexWrap: 'wrap',
                                justifyContent: 'center',
                                padding: '4px'
                              }}>
                              {tags.length > 0 ? (
                                tags.map((tag, idx) => <TagChip key={`${row.id}-tag-${idx}`} label={tag} />)
                              ) : (
                                <Typography level='body-sm' sx={{ color: 'text.tertiary' }}>
                                  -
                                </Typography>
                              )}
                            </Box>
                          </td>
                        )
                      } else if (key === 'volume') {
                        // 处理 volume 列，添加颜色标识
                        const volumeValue = row[key] || ''
                        const volumeColor = getVolumeColor(volumeValue)
                        return (
                          <td key={`${key}-${row.id}`} style={{ textAlign: 'left' }}>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, paddingLeft: '8px' }}>
                              <Box
                                sx={{
                                  width: '12px',
                                  height: '12px',
                                  borderRadius: '2px',
                                  backgroundColor: volumeColor,
                                  flexShrink: 0
                                }}
                              />
                              <Typography level='body-sm'>{volumeValue}</Typography>
                            </Box>
                          </td>
                        )
                      } else {
                        return <td key={`${key}-${row.id}`}>{row[key] || ''}</td>
                      }
                    })}
                  </tr>
                )
              })}
            {emptyRows > 0 && (
              <tr
                style={
                  {
                    height: `calc(${emptyRows} * 40px)`,
                    '--TableRow-hoverBackground': 'transparent'
                  } as React.CSSProperties
                }>
                <td colSpan={tableKeys.length + 1} aria-hidden />
              </tr>
            )}
          </tbody>
        </Table>
      </Sheet>
      {/* 分页组件 */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mt: 2, // 在表格下方添加间距
          padding: '0px 8px 8px 8px',
          // borderTop: '1px solid #ddd',
          backgroundColor: 'white'
        }}>
        {/* 左侧 - 显示总文件数 */}
        {/* <Typography sx={{ textAlign: 'center', minWidth: 80, fontWeight: '400', fontSize: '14px' }}>
          Total of <strong style={{ fontWeight: 600 }}>{tableData.length}</strong> Files
        </Typography> */}

        {/* 右侧 - 选择每页显示条目 + 分页信息 + 翻页按钮 */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
          {/* 选择每页条目数 */}
          <FormControl orientation='horizontal' size='sm'>
            {/* <FormLabel sx={{ fontWeight: '300', fontSize: '18px' }}>Show</FormLabel> */}
            <Select onChange={handleChangeRowsPerPage} value={rowsPerPage}>
              <Option value={50}>50</Option>
              <Option value={100}>100</Option>
              <Option value={150}>150</Option>
            </Select>
            <FormLabel sx={{ fontWeight: '300', fontSize: '18px', paddingLeft: '5px' }}>Entries</FormLabel>
          </FormControl>

          {/* 显示当前分页信息 */}
          <Typography sx={{ textAlign: 'center', minWidth: 80, fontWeight: '300', fontSize: '18px' }}>
            Showing <strong>{tableData.length === 0 ? 0 : page * rowsPerPage + 1}</strong> -{' '}
            <strong>{getLabelDisplayedRowsTo()}</strong> of <strong>{tableData.length}</strong> files
          </Typography>

          {/* 翻页按钮 */}
          <Box sx={{ display: 'flex', gap: 1 }}>
            <IconButton
              size='sm'
              color='neutral'
              variant='outlined'
              disabled={page === 0}
              onClick={() => handleChangePage(page - 1)}
              sx={{ bgcolor: 'background.surface' }}>
              <KeyboardArrowLeftIcon />
            </IconButton>
            <IconButton
              size='sm'
              color='neutral'
              variant='outlined'
              disabled={tableData.length !== -1 ? page >= Math.ceil(tableData.length / rowsPerPage) - 1 : false}
              onClick={() => handleChangePage(page + 1)}
              sx={{ bgcolor: 'background.surface' }}>
              <KeyboardArrowRightIcon />
            </IconButton>
          </Box>
        </Box>
        <Stack direction='row' spacing={2}>
          <Button
            sx={{ border: '1px solid #ced7e1' }}
            onClick={onClickApply}
            variant='solid'
            size='lg'
            startDecorator={<DoneAllRounded />}>
            Apply
          </Button>
          <Button
            sx={{ border: '1px solid #ced7e1' }}
            color='neutral'
            variant='plain'
            size='lg'
            onClick={() => {
              setSelected([])
              window.parent.postMessage({ type: 'datahub:apply' }, window.location.origin)
            }}
            startDecorator={<CancelRounded />}>
            Cancel
          </Button>
        </Stack>
      </Box>
      <Box
        sx={{
          width: '100%',
          display: 'flex',
          mb: 1,
          gap: 1,
          flexDirection: { xs: 'column', sm: 'row' },
          alignItems: { xs: 'start', sm: 'center' },
          flexWrap: 'wrap',
          justifyContent: 'space-between'
        }}>
        {/* <Typography level='title-lg'>
          <span style={{ fontSize: '34px' }}>{selected.length}</span> Data files selected
        </Typography> */}
      </Box>
      <Snackbar
        autoHideDuration={3000}
        open={snackbarShow}
        variant='solid'
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
        onClose={(event, reason) => {
          if (reason === 'clickaway') {
            return
          }
          setSnackbarShow(false)
        }}>
        {snackbarContent}
      </Snackbar>
    </>
  )
}

export default memo(TrackTable)
