import React, { memo, useEffect } from 'react'
import type { FC, ReactNode } from 'react'
import { Box, Button, Stack, Typography } from '@mui/joy'
import BMSelectorItem, { IBMSelectorItem } from './selector_item'

export interface IBMSelectorData {
  name: string
  title: string
  expanded: boolean
  value: { id: string; name: any; number: number; percentage: number }[]
}

interface Iprops {
  children?: ReactNode
  selectorData: IBMSelectorData[]
  resetFilters: boolean
  onCallBack: (title: string, data: IBMSelectorItem[]) => void
}

const BMDataSelector: FC<Iprops> = (props) => {
  const { selectorData, resetFilters, onCallBack } = props
  const [selectorHeight, setSelectorHeight] = React.useState(window.innerHeight - 80)

  React.useEffect(() => {
    window.addEventListener('resize', () => {
      setSelectorHeight(window.innerHeight - 80)
    })
  }, [])

  useEffect(() => {
    console.log('expandedAll', selectorData)
  }, [selectorData])

  const handlerSelectorCallBack = (name: string, data: IBMSelectorItem[]) => {
    console.log('BMDataSelector handlerSelectorCallBack', name, data)
    onCallBack(name, data)
  }

  return (
    <>
      <Box>
        {/* <Typography sx={{ fontWeight: 400, fontSize: '16px', padding: '10px', background: '#57606f', color: 'white' }}>
          Track Selector
        </Typography> */}
        <Box
          // display='flex'
          // flexDirection='column'
          // gap={1}
          sx={{ paddingTop: '0.25rem', overflowY: 'scroll', height: selectorHeight }}>
          {selectorData.map((item, index) => (
            <BMSelectorItem
              key={index}
              name={item.name}
              title={item.title}
              expanded={item.expanded}
              data={item.value}
              resetFilters={resetFilters}
              onCallBack={handlerSelectorCallBack}
            />
          ))}
          {/* <BMSelectorItem title='Volumn' data={initialData} onCallBack={handlerSelectorCallBack} /> */}
        </Box>
      </Box>
    </>
  )
}

export default memo(BMDataSelector)
